 let m=Math.floor((l+r)/2);
 let node=new Node(a[m]);
 node.left=build(a,l,m-1);
 node.right=build(a,m+1,r);
 return node;
}

function build(preL,preR,inL,inR){
 if(preL>preR) return null;
 let rootVal=pre[preL];
 let k=idx.get(rootVal);
 let leftSize=k-inL;
 let node=new Node(rootVal);
 node.left=build(preL+1,preL+leftSize,inL,k-1);
 node.right=build(preL+leftSize+1,preR,k+1,inR);
 return node;
}

while(cur){
 if(!cur.left){ visit(cur); cur=cur.right; }
 else {
  let p=cur.left;
  while(p.right && p.right!==cur) p=p.right;
  if(!p.right){ p.right=cur; cur=cur.left; }
  else { p.right=null; visit(cur); cur=cur.right; }
 }
}

function build(idx,l,r){
